  ('pukao-6f0ba476-moex-00429', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '隨著經濟與社會的發展，當體系中平均每人所得增加時，政府的公共支出會呈現遞增式的成長， 此現象稱之為：', '["外部效果", "位移效果", "華格納法則", "不平衡成長理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00430', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '政府為達成經濟、社會或其他特定政策目標，利用租稅優惠方式，使特定對象獲得租稅利益之補 貼，此稱為：', '["財政幻覺", "稅式支出", "擴張性財政政策", "所得重分配"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00431', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', 'G1、G2與G3分別代表某公共財的三種不同規模，由小至大排序為G1、G2與G3。今有甲、乙、 丙三位選民，甲的偏好為 G1>G2>G3，乙的偏好為 G3>G1>G2，丙的偏好為 G2>G3>G1，此處 Gi>Gj代表選民偏好Gi優於Gj。下列敘述何者正確？', '["甲的偏好為多峰", "乙的偏好為單峰", "兩兩對決的多數決投票結果滿足遞移性", "中位數選民定理無法成立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00432', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '現有一組決策成本線與外部成本線，且兩條線隨同意門檻的增加，呈嚴格遞增或遞減改變。今有 三種不同的同意門檻，門檻a之決策成本與外部成本均為10；門檻b之決策成本為15，外部成本 為7；門檻c之決策成本為8，外部成本為14。根據最適憲政模型，a、b、c之間的關係最可能為 下列何者？', '["a<b<c", "b<a<c", "b<c<a", "c<a<b"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00433', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '亞羅認為一個良好的投票法則應具備之性質，不包括下列何者？', '["投票法則應能對所有議題予以排序", "所有選民的偏好均為單峰", "不相關議題具獨立性", "不應有獨裁者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00434', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '社會保險財務處理方式中，基金（或安全準備金）的投資運用，下列何者較不涉及長期收益？', '["隨收隨付制", "完全儲備制", "部分儲備制", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00435', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '關於在社會保險及商業保險等二者中的逆選擇問題，下列敘述何者錯誤？', '["社會保險的逆選擇發生率會高於商業保險", "社會保險與商業保險的逆選擇情況都是起因於資訊不對稱", "透過擴大強制納保對象可以降低社會保險的逆選擇問題", "透過強化核保可以降低商業保險的逆選擇問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00436', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '在部分均衡分析架構下，對完全競爭市場之消費者或生產者課從量貨物稅，下列敘述何者正確？', '["對消費者課均衡價格較高", "對生產者課均衡價格較低", "對消費者課均衡數量較低", "稅後均衡數量相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00437', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '假如家計單位在預算限制下，選擇休閒與其他財貨來追求效用極大，當政府課徵比例薪資所得稅 時，下列敘述何者正確？', '["當休閒為正常財時，所得效果會使稅後的休閒變多", "當休閒為劣等財時，所得效果會使稅後的休閒變少", "當休閒為正常財時，替代效果會使稅後的休閒變多", "當休閒為劣等財時，替代效果會使稅後的休閒變少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00438', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '在哈柏格租稅歸宿的一般均衡分析法中，若對某一產業的商品課稅，則生產該商品較密集使用的 生產要素相對價格會：', '["降低", "提高", "不變", "不確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "5624fb6b2743", "answer_pdf_sha1": "e8f23e803819", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
